INSERT INTO public.documents (id, title, content, summary, images, notion_page_id, group_id, x, y, created_at, updated_at) VALUES (8, 'SUB 회의별·인터뷰별 통합 정리', '정리 기준: SUB 워크스페이스 회의록 전체 및 인터뷰/리서치 문서
정리 원칙:
- 회의 간 구분 유지
- 생략 최소화
- 회의별 표 + 인터뷰별 표 중심으로 재구성
- 현재 확보된 문서 내용만 바탕으로 정리

## 1. 회의별 표
